/* ---------------- Live Site Data (Supabase, with default fallback) ---------------- */
const SiteDataContext = createContext(null);
function useSiteData() {
  return useContext(SiteDataContext);
}

function SiteDataProvider({ children }) {
  const [settings, setSettings] = useState(null);
  const [services, setServices] = useState(null);
  const [testimonials, setTestimonials] = useState(null);
  const [caseStudies, setCaseStudies] = useState(null);

  useEffect(() => {
    let cancelled = false;

    supabase
      .from("site_settings")
      .select("*")
      .eq("id", 1)
      .single()
      .then(({ data }) => {
        if (!cancelled && data) setSettings(data);
      });

    supabase
      .from("services")
      .select("*")
      .order("sort_order")
      .then(({ data }) => {
        if (!cancelled && data && data.length) {
          setServices(
            data.map((s) => ({
              n: s.number_label,
              id: s.id,
              title: s.title,
              img: s.image_url || MARKETING,
              desc: s.description,
              features: s.features || [],
            }))
          );
        }
      });

    supabase
      .from("testimonials")
      .select("*")
      .order("sort_order")
      .then(({ data }) => {
        if (!cancelled && data && data.length) {
          setTestimonials(data.map((t) => ({ name: t.name, role: t.role, quote: t.quote, rating: t.rating })));
        }
      });

    supabase
      .from("case_studies")
      .select("*")
      .order("sort_order")
      .then(({ data }) => {
        if (!cancelled && data && data.length) {
          setCaseStudies(data.map((c) => ({ metric: c.metric, suffix: c.suffix, label: c.label, sub: c.sub_text })));
        }
      });

    return () => {
      cancelled = true;
    };
  }, []);

  const value = {
    whatsappLink: settings?.whatsapp ? `https://wa.me/${settings.whatsapp}` : DEFAULT_WHATSAPP_LINK,
    phoneLink: settings?.phone ? `tel:${settings.phone}` : DEFAULT_PHONE_LINK,
    phoneDisplay: settings?.phone || DEFAULT_PHONE_DISPLAY,
    fbLink: settings?.facebook_url || DEFAULT_FB_LINK,
    ytLink: settings?.youtube_url || DEFAULT_YT_LINK,
    mailLink: settings?.email ? `mailto:${settings.email}` : DEFAULT_MAIL_LINK,
    emailDisplay: settings?.email || DEFAULT_EMAIL_DISPLAY,
    logoUrl: settings?.logo_url || DEFAULT_LOGO_URL,
    address: settings?.address || DEFAULT_ADDRESS,
    hours: settings?.business_hours || DEFAULT_HOURS,
    heroBadge: settings?.hero_badge || DEFAULT_HERO_BADGE,
    heroHeadline: settings?.hero_headline || DEFAULT_HERO_HEADLINE,
    heroSubheadline: settings?.hero_subheadline || DEFAULT_HERO_SUBHEADLINE,
    services: services || DEFAULT_SERVICES,
    testimonials: testimonials || DEFAULT_TESTIMONIALS,
    caseStudies: caseStudies || DEFAULT_CASE_STUDIES,
  };

  return <SiteDataContext.Provider value={value}>{children}</SiteDataContext.Provider>;
}

