/* ---------------- Velocity Line (signature signal trace) ---------------- */
function VelocityLine({ height = 220, animate = true }) {
  const pathRef = useRef(null);
  const [len, setLen] = useState(0);
  useEffect(() => {
    if (pathRef.current) setLen(pathRef.current.getTotalLength());
  }, []);
  // a jagged-to-smooth ascending signal line, like a campaign performance trace
  const d = "M0,170 L40,150 L75,160 L110,95 L150,115 L190,55 L235,80 L280,30 L330,45 L380,5";
  return (
    <svg viewBox="0 0 380 200" width="100%" height={height} preserveAspectRatio="none" style={{ overflow: "visible" }}>
      <defs>
        <linearGradient id="vlGrad" x1="0" y1="0" x2="1" y2="0">
          <stop offset="0%" stopColor="#2F6BFF" stopOpacity="0.2" />
          <stop offset="100%" stopColor="#5B8CFF" stopOpacity="1" />
        </linearGradient>
        <filter id="vlGlow" x="-50%" y="-50%" width="200%" height="200%">
          <feGaussianBlur stdDeviation="4" result="blur" />
          <feMerge>
            <feMergeNode in="blur" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>
      </defs>
      <path
        ref={pathRef}
        d={d}
        fill="none"
        stroke="url(#vlGrad)"
        strokeWidth="2.5"
        strokeLinecap="round"
        strokeLinejoin="round"
        filter="url(#vlGlow)"
        style={
          animate && len
            ? {
                strokeDasharray: len,
                strokeDashoffset: len,
                animation: "tg-draw 2.4s cubic-bezier(.2,.7,.2,1) 0.3s forwards",
              }
            : undefined
        }
      />
      {[
        [0, 170],
        [110, 95],
        [190, 55],
        [280, 30],
        [380, 5],
      ].map(([x, y], i) => (
        <circle
          key={i}
          cx={x}
          cy={y}
          r="3.5"
          fill="#0B0F1A"
          stroke="#5B8CFF"
          strokeWidth="2"
          style={{
            opacity: animate ? 0 : 1,
            animation: animate ? `tg-dot-in 0.5s ease ${1.8 + i * 0.15}s forwards` : undefined,
          }}
        />
      ))}
    </svg>
  );
}

